SELECT "Invoice" AS DocType, [Purch_ Inv_ Line].Type, [Purch_ Inv_ Header].No_, [Purch_ Inv_ Header].[VAT Registration No_], [Purch_ Inv_ Header].[Pay-to name], [Purch_ Inv_ Header].[Pay-to Country_Region Code], Item.[Country_Region of Origin Code], Item.[Tariff No_], Val([item.Gross Weight])*Val([no_ of pairs]) AS PesoLordo, Val([no_ of pairs]) AS Unita, Item.Description, Val([Amount]) AS ImportoNetto, Val([Amount])+Val([inv_ discount amount])+Val([Line discount amount]) AS ImportoLordo, Item.[Trademark Code] AS Marchio, Vendor.Name AS Fornitore, [Purch_ Inv_ Header].[Posting Date] AS DataRegistrazione, IIf([purch_ inv_ line.Gen_ Bus_ Posting Group]="NAZIONALE","ITALIA","ESTERO") AS Paese, [Purch_ Inv_ Header].[Currency Code] AS Valuta
FROM ([Purch_ Inv_ Line] INNER JOIN [Purch_ Inv_ Header] ON [Purch_ Inv_ Line].[Document No_] = [Purch_ Inv_ Header].No_) INNER JOIN (Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) ON [Purch_ Inv_ Line].No_ = Item.No_
WHERE ((([Purch_ Inv_ Line].Type)=19 Or ([Purch_ Inv_ Line].Type)=20) AND (([Purch_ Inv_ Header].[Posting Date]) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]) AND ((Item.[advertising material])=0));

